 {
     if (type->IsETSAnyType() || type->DefinitelyNotETSNullish() || type->IsETSNullType()) {
         return type;
     }

     if (type->IsETSTypeParameter()) {
         // Strict equality produces incorrect NonNullish types #21526
         return type;
     }

     if (type->IsETSPartialTypeParameter()) {
         return type;
     }

