     ES2PANDA_ASSERT(node->IsAssignmentExpression() || node->IsBinaryExpression());
     ES2PANDA_ASSERT(Checker()->Relation()->IsIdenticalTo(GetAccumulatorType(), node->AsExpression()->TsType()));
 }

