void ETSChecker::CheckReadonlyClassPropertyInImplementedInterface(ETSObjectType *classType,
                                                                  varbinder::LocalVariable *field)
{
    const auto searchFlag = PropertySearchFlags::SEARCH_ALL | PropertySearchFlags::SEARCH_IN_BASE |
                            PropertySearchFlags::SEARCH_IN_INTERFACES |
                            PropertySearchFlags::DISALLOW_SYNTHETIC_METHOD_CREATION;
    const auto &interfaceList = GetInterfaces(classType);
    if (field == nullptr || field->Declaration() == nullptr || field->Declaration()->Node() == nullptr ||
        !field->Declaration()->Node()->IsClassProperty() ||
        !field->Declaration()->Node()->AsClassProperty()->IsReadonly()) {
        return;
    }

    for (auto *interface : interfaceList) {
        ES2PANDA_ASSERT(interface != nullptr);
        auto *propertyFound = interface->GetProperty(field->Name(), searchFlag);
        if (propertyFound == nullptr) {
            continue;
        }

        ES2PANDA_ASSERT(propertyFound->TsType() != nullptr);
        if (!propertyFound->TsType()->IsETSFunctionType()) {
            continue;
        }

        auto setter = propertyFound->TsType()->AsETSFunctionType()->FindSetter();
        if (setter != nullptr) {
            LogError(diagnostic::INTERFACE_PROPERTY_REQUIRES_SETTER, {interface->Name(), field->Name()},
                     field->Declaration()->Node()->Start());
        }
    }
}

// After Recheck/Rebind, OriginalNode() may not match field->Declaration()->Node() for the same logical property.
// Match by accessor name + ClassProperty in OriginalNode (pointer or same name with GETTER_SETTER); scan overloads.
static bool IsSyntheticAccessorForProperty(ir::MethodDefinition *method, util::StringView propName,
                                           ir::ClassProperty *prop)
{
    auto *func = method->Function();
    if (func == nullptr || (!func->IsGetter() && !func->IsSetter())) {
        return false;
    }
    if (!method->Key()->IsIdentifier() || method->Key()->AsIdentifier()->Name() != propName) {
        return false;
    }
    auto *on = method->OriginalNode();
    if (on == nullptr || !on->IsClassProperty()) {
        return false;
    }
    auto *onProp = on->AsClassProperty();
    if (onProp == prop) {
        return true;
    }
    if (!onProp->Key()->IsIdentifier() || onProp->Key()->AsIdentifier()->Name() != propName) {
        return false;
    }
    return (onProp->Modifiers() & ir::ModifierFlags::GETTER_SETTER) != 0U;
}

static bool MethodTreeHasGeneratedAccessor(ir::MethodDefinition *root, util::StringView propName,
                                           ir::ClassProperty *prop)
{
    if (root == nullptr) {
        return false;
    }
    if (IsSyntheticAccessorForProperty(root, propName, prop)) {
        return true;
    }
    for (auto *o : root->Overloads()) {
        if (MethodTreeHasGeneratedAccessor(o, propName, prop)) {
            return true;
        }
    }
    return false;
}

